#include <vector>

class Solution {
public:
    int rand10(int n) {
        std::vector<int> result(n);
        int rand7_count = 0;

        for (int i = 0; i < n; i++) {
            result[i] = rand7();
            rand7_count++;
        }

        for (int i = 0; i < n; i++) {
            result[i] = result[i] * 2 + 3;
        }

        return rand7_count;
    }
};
